#!/usr/bin/env python3
"""Extract Page-dependent top-level definitions from Wagtail production files."""
import re
from pathlib import Path

ROOT = Path('/Users/luc/Developer/luuuc/oss/sense-benchmark/baseline/wagtail/wagtail')
EXCLUDE_DIRS = {'test', 'tests', '__pycache__', 'migrations', 'locale', 'templates', 'static'}
EXCLUDE_FILES = {'tests.py'}

# Patterns that indicate a Page dependency
PAGE_REFS = [
    re.compile(r'\bPage\b'),
    re.compile(r'\bAbstractPage\b'),
    re.compile(r'\bPageViewRestriction\b'),
    re.compile(r'\bGroupPagePermission\b'),
    re.compile(r'\bPageLogEntry\b'),
    re.compile(r'\bPageSubscription\b'),
    re.compile(r'\bWorkflowPage\b'),
    re.compile(r'\bPagePermissionTester\b'),
    re.compile(r'\bget_page_models\b'),
    re.compile(r'\bget_page_content_types\b'),
    re.compile(r'\bget_default_page_content_type\b'),
    re.compile(r'\bpage_published\b|\bpage_unpublished\b|\bpage_slug_changed\b|\bpre_page_move\b|\bpost_page_move\b'),
]

def is_excluded(path: Path) -> bool:
    parts = path.parts
    if any(part in EXCLUDE_DIRS for part in parts):
        return True
    if path.name in EXCLUDE_FILES or path.name.startswith('test_'):
        return True
    return False

def has_page_ref(text):
    for pattern in PAGE_REFS:
        if pattern.search(text):
            return True
    return False

# Regex to find top-level class/function definitions
def_re = re.compile(r'^(class|def)\s+(\w+)\s*[\(:]')

results = []
for path in sorted(ROOT.rglob('*.py')):
    if is_excluded(path):
        continue
    try:
        text = path.read_text(encoding='utf-8')
    except UnicodeDecodeError:
        continue
    if not has_page_ref(text):
        continue

    lines = text.splitlines()
    definitions = []
    for i, line in enumerate(lines, 1):
        match = def_re.match(line)
        if match:
            definitions.append((i, match.group(2), match.group(1)))

    # For each definition, check if the body (up to next top-level definition) has Page ref
    for idx, (start, name, kind) in enumerate(definitions):
        end = len(lines) if idx == len(definitions) - 1 else definitions[idx + 1][0] - 1
        body = '\n'.join(lines[start-1:end])
        if has_page_ref(body):
            results.append(f'{path}:{start}')

print('\n'.join(results))
print(f'\nTotal: {len(results)}', file=__import__('sys').stderr)

